<?php $heading='Build Your Career With Advance Care';$subheading='Join a multidisciplinary team committed to compassionate and modern healthcare.';require __DIR__.'/../public/_hero.php';?><section class="section"><div class="section-title"><span>OPEN POSITIONS</span><h2>Current opportunities</h2></div><div class="business-grid"><?php foreach($jobs as$j):?><article class="business-card"><span class="status-pill confirmed"><?=e(ucwords(str_replace('_',' ',$j['employment_type'])))?></span><h2><?=e($j['title'])?></h2><p><?=e($j['department'])?> · <?=e($j['location'])?></p><p><?=e($j['summary'])?></p><div class="business-meta"><b><?=$j['vacancy']?> vacancy</b><span>Apply by <?=date('d M Y',strtotime($j['application_deadline']))?></span></div><a class="btn" href="<?=url('career?id='.$j['id'])?>">View and Apply</a></article><?php endforeach;?></div><?php if(!$jobs):?><div class="empty">There are no open positions right now.</div><?php endif;?></section>
